//! Bowl-Mesh Attention-Head Q-Filter
//! =================================
//!
//! Rust mirror of `Gnosis.EchoChamberAsTaoBowl` (see
//! `open-source/gnosis-math/Gnosis/EchoChamberAsTaoBowl.lean`).
//!
//! ## Why this exists (replaces the falsified binary mask)
//!
//! The binary standing-wave mask in [`crate::standing_wave_pinning`] was
//! falsified on 2026-05-03 — see
//! `STANDING_WAVE_STATUS_2026_05_03_AFTER_FALSIFICATION.md` in this crate.
//! Strict K=1 PCA-only acceptance was 0/79 on Qwen-0.5B; the projected
//! Qwen-Coder-7B path measured 0/30 net rollbacks. The root cause is that
//! `decompress_from_standing` (and any equivalent binary mask) zero-fills
//! non-standing dims, which destroys the cross-layer residual sum the
//! transformer relies on: `h_{n+1} = h_n + f(h_n)` cannot tolerate
//! zeroing destructive dims because the next layer still reads them.
//!
//! The bowl model damps off-resonance dims instead of zeroing them, so the
//! residual add is preserved. Each attention head is read as a Tao bowl:
//! `rim`, `void`, `rigidity`, `damping` are finite Nat dials that determine
//! the bowl's fundamental resonant mode and its Q. A dim at the fundamental
//! gets amplified by Q; an off-mode dim gets attenuated by `damping + 1` —
//! never zeroed unless damping is large enough to round it to 0 by integer
//! truncation.
//!
//! ## Status
//!
//! NOT YET wired into `model.rs` attention path. This is the standalone
//! primitive whose Rust ↔ Lean parity needs to land first; integration into
//! the attention path is a separate follow-up.

#![allow(dead_code)]

/// One attention-head's Tao bowl: dim-resolved Q-filter parameters.
///
/// `rim`, `void`, `rigidity`, `damping` mirror the `TaoBowl` Nat fields in
/// Lean. `fundamental_dim` selects which residual dim is treated as the
/// bowl's fundamental mode; `hidden_dim` is the residual width the filter
/// applies to.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct BowlMeshHead {
    pub rim: u32,
    pub void: u32,
    pub rigidity: u32,
    pub damping: u32,
    pub fundamental_dim: u32,
    pub hidden_dim: u32,
}

impl BowlMeshHead {
    pub fn new(
        rim: u32,
        void: u32,
        rigidity: u32,
        damping: u32,
        fundamental_dim: u32,
        hidden_dim: u32,
    ) -> Self {
        BowlMeshHead {
            rim,
            void,
            rigidity,
            damping,
            fundamental_dim,
            hidden_dim,
        }
    }

    /// Mirror of Lean `fundamentalMode`:
    ///   `if void = 0 then 0 else (rim * rigidity) / void`
    /// A filled bowl (void = 0) has no resonant mode.
    pub fn fundamental_mode(&self) -> u32 {
        if self.void == 0 {
            0
        } else {
            self.rim.saturating_mul(self.rigidity) / self.void
        }
    }

    /// Mirror of Lean `qFactor`:
    ///   `if damping = 0 then 0 else (rim * rigidity) / damping`
    /// Zero damping returns 0 as a finite sentinel (matches the Lean
    /// definition's `damping = 0` case); the high-Q regime is exposed via
    /// `is_pejorative_echo`.
    pub fn q_factor(&self) -> u32 {
        if self.damping == 0 {
            0
        } else {
            self.rim.saturating_mul(self.rigidity) / self.damping
        }
    }

    /// Mirror of Lean `freqMismatch`:
    ///   `let m := fundamentalMode b; if m ≤ f then f - m else m - f`
    pub fn freq_mismatch(&self, freq: u32) -> u32 {
        let m = self.fundamental_mode();
        freq.abs_diff(m)
    }

    /// Per-dim Q-filter on a residual amplitude.
    ///
    /// On resonance (`freq_mismatch == 0`): returns `amp * q_factor`.
    /// Off resonance: returns `amp / (damping + 1)`.
    ///
    /// Non-destructive by construction. The off-resonance path divides by
    /// `damping + 1`, so `damping = 0` is a passthrough (returns `amp`)
    /// rather than a zero — this is the degenerate-bowl case and is
    /// **distinct from the binary mask**, which would have zeroed it. The
    /// pinned distinction is what preserves the residual sum across layers.
    pub fn q_filter(&self, amp: f32, freq_idx: u32) -> f32 {
        if self.freq_mismatch(freq_idx) == 0 {
            amp * self.q_factor() as f32
        } else {
            amp / (self.damping as f32 + 1.0)
        }
    }

    /// In-place apply `q_filter` per dim index. `freq_idx` is the dim index,
    /// not a physical frequency — the residual is indexed in the bowl's own
    /// dim-as-frequency interpretation.
    pub fn route_residual(&self, residual: &mut [f32]) {
        assert_eq!(
            residual.len() as u32,
            self.hidden_dim,
            "route_residual: residual length must equal hidden_dim"
        );
        for (i, slot) in residual.iter_mut().enumerate() {
            *slot = self.q_filter(*slot, i as u32);
        }
    }

    /// Mirror of `IsFilledBowl`: no void, no function.
    pub fn is_filled_bowl(&self) -> bool {
        self.void == 0
    }

    /// Mirror of `IsEmptyBowl`: no rim, no chamber.
    pub fn is_empty_bowl(&self) -> bool {
        self.rim == 0
    }

    /// Mirror of `IsPejorativeEcho`: Q ≥ 100.
    pub fn is_pejorative_echo(&self) -> bool {
        self.q_factor() >= 100
    }

    /// Convenience constructor for the `bowl-q-sweep` harness. Fills
    /// `rim`, `void`, `rigidity` with the `balancedBowl` Lean witness's
    /// values (5, 5, 3) and sets the documentary `fundamental_dim` to
    /// match the bowl's intrinsic `fundamental_mode()` (= 3 for those
    /// defaults). Only `damping` is the sweep knob.
    ///
    /// Note: `fundamental_dim` is documentary on both Lean and Rust
    /// sides. The actual on-resonance dim used by `q_filter` /
    /// `route_residual` is derived from `(rim, rigidity, void)` via
    /// `fundamental_mode()` — so the sweep exercises 1 on-resonance dim
    /// (at index `fundamental_mode() = 3`) and `hidden_dim - 1`
    /// off-resonance dims.
    pub fn for_sweep(hidden_dim: u32, damping: u32) -> Self {
        let rim = 5;
        let void = 5;
        let rigidity = 3;
        let fundamental_dim = (rim * rigidity) / void;
        Self::new(rim, void, rigidity, damping, fundamental_dim, hidden_dim)
    }

    /// Non-mutating apply: returns a Q-filtered copy of `residual`.
    /// Wrapper around `route_residual` for callers that want functional
    /// style.
    pub fn apply(&self, residual: &[f32]) -> Vec<f32> {
        let mut out = residual.to_vec();
        self.route_residual(&mut out);
        out
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Fundamental dim with positive amp is amplified by Q (≥ amp when Q ≥ 1).
    /// Uses the balanced-bowl Lean witness: rim=5, void=5, rigidity=3,
    /// damping=1, so fundamental_mode = (5*3)/5 = 3 and q_factor = (5*3)/1 = 15.
    #[test]
    fn q_filter_on_resonance_amplifies() {
        let head = BowlMeshHead::new(5, 5, 3, 1, 3, 8);
        assert_eq!(head.fundamental_mode(), 3);
        assert_eq!(head.q_factor(), 15);
        let out = head.q_filter(1.0, 3);
        assert!(out >= 1.0, "on-resonance Q-filter must amplify (got {out})");
        assert!((out - 15.0).abs() < 1e-6, "expected amp*Q = 15, got {out}");
    }

    /// Off-resonance with damping=0 is the Q-amplifier-collapse degenerate:
    /// divides by `damping + 1 = 1`, so off-resonance returns the input amp
    /// unchanged. This is the OPPOSITE failure mode from the binary mask —
    /// the mask is the HIGH-damping limit (see
    /// `q_filter_high_damping_crushes_off_resonance` below and
    /// `Gnosis/BowlMeshNode.lean::mask_at_high_damping`). At damping=0,
    /// off-mode amp is preserved but on-resonance gain collapses because
    /// `q_factor` is pinned to 0 by `qFactor_eq_zero_of_damping_eq_zero`.
    #[test]
    fn q_filter_off_resonance_damping_zero_is_passthrough() {
        let head = BowlMeshHead::new(5, 5, 3, 0, 3, 8);
        let out = head.q_filter(7.0, 0); // dim 0, fundamental is 3 → mismatch=3
        assert!(
            (out - 7.0).abs() < 1e-6,
            "damping=0 must pass amp through, got {out}"
        );
    }

    /// Off-resonance with damping=4 attenuates by 1/(damping+1) = 1/5.
    #[test]
    fn q_filter_off_resonance_damping_four_attenuates_by_fifth() {
        let head = BowlMeshHead::new(5, 5, 3, 4, 3, 8);
        let out = head.q_filter(10.0, 0); // dim 0 off-mode
        let expected = 10.0_f32 / 5.0;
        assert!(
            (out - expected).abs() < 1e-6,
            "expected ~{expected}, got {out}"
        );
    }

    /// route_residual on a non-zero vector never zeroes everything when
    /// damping ≥ 1. The whole point: residual stream survives the filter.
    #[test]
    fn route_residual_preserves_nonzero_stream() {
        let head = BowlMeshHead::new(5, 5, 3, 1, 3, 8);
        let mut residual = vec![1.0_f32; 8];
        head.route_residual(&mut residual);
        let any_nonzero = residual.iter().any(|v| v.abs() > 0.0);
        assert!(
            any_nonzero,
            "residual stream went all-zero — bowl filter is destructive: {:?}",
            residual
        );
        // On-resonance dim is amplified; off-resonance dims are halved
        // (damping+1 = 2), so off-mode entries are 0.5 — non-zero.
        assert!((residual[3] - 15.0).abs() < 1e-6);
        assert!((residual[0] - 0.5).abs() < 1e-6);
    }

    /// is_filled_bowl matches `void == 0`; pejorative-echo boundary at Q ≥ 100.
    /// Uses the Lean `pejorativeBowl` witness verbatim: rim=10, void=2,
    /// rigidity=100, damping=1 → q = (10*100)/1 = 1000 ≥ 100.
    #[test]
    fn boundary_filled_bowl_and_pejorative_echo() {
        let filled = BowlMeshHead::new(5, 0, 3, 1, 0, 8);
        assert!(filled.is_filled_bowl());
        assert!(!filled.is_empty_bowl());
        assert_eq!(
            filled.fundamental_mode(),
            0,
            "filled bowl must have no mode"
        );

        let empty = BowlMeshHead::new(0, 5, 3, 1, 0, 8);
        assert!(empty.is_empty_bowl());
        assert!(!empty.is_filled_bowl());

        let pejorative = BowlMeshHead::new(10, 2, 100, 1, 0, 8);
        assert_eq!(pejorative.q_factor(), 1000);
        assert!(pejorative.is_pejorative_echo());

        // Just-below boundary: q_factor = 99 should NOT trip the predicate.
        let sub = BowlMeshHead::new(99, 2, 1, 1, 0, 8);
        assert_eq!(sub.q_factor(), 99);
        assert!(!sub.is_pejorative_echo());

        // At-boundary: q_factor = 100 should trip (≥ 100).
        let at = BowlMeshHead::new(100, 2, 1, 1, 0, 8);
        assert_eq!(at.q_factor(), 100);
        assert!(at.is_pejorative_echo());
    }

    /// HIGH-damping mask regime — the binary-mask analogue. With
    /// `damping = 99` and `amp = 10` off-resonance, the Lean `Nat`
    /// path truncates `10 / 100` to `0` (see
    /// `BowlMeshRuntimeOracle.lean::highDamping_runtime_oracle_mask_regime`);
    /// f32 returns `0.1`. The qualitative claim — off-resonance
    /// vanishes relative to on-resonance — is preserved across both
    /// arithmetics. The exact-zero gap between Lean and Rust is the
    /// only contract that differs across the Oracle pentad (Contract
    /// #3 in `BOWL_MESH_FALSIFIABILITY.md §6`).
    #[test]
    fn q_filter_high_damping_crushes_off_resonance() {
        let head = BowlMeshHead::new(5, 5, 3, 99, 3, 8);
        let out = head.q_filter(10.0, 7); // mismatch 4 → off-resonance
        assert!(
            out < 0.2,
            "high damping must crush off-resonance toward zero, got {out}"
        );
        assert!((out - 0.1).abs() < 1e-6, "expected ~0.1, got {out}");
        // Monotone crush: damping = 999 attenuates further than 99.
        let crusher = BowlMeshHead::new(5, 5, 3, 999, 3, 8);
        let further = crusher.q_filter(10.0, 7);
        assert!(
            further < out,
            "damping=999 must attenuate more than damping=99 (got {further} vs {out})"
        );
    }

    /// Lean → Rust runtime oracle pentad parity. Mirrors
    /// `Gnosis/BowlMeshRuntimeOracle.lean::bowl_mesh_runtime_oracle_pentad`
    /// exactly. Each assertion below corresponds to one
    /// `*_runtime_oracle_*` theorem; Contract #3 is the documented
    /// arithmetic gap (Lean `Nat` 0 vs Rust f32 0.1) called out in
    /// `BOWL_MESH_FALSIFIABILITY.md §6`.
    #[test]
    fn runtime_oracle_pentad_parity() {
        // #1: balancedBowl on-resonance — Lean: 150.
        let balanced = BowlMeshHead::new(5, 5, 3, 1, 3, 8);
        assert_eq!(balanced.q_filter(10.0, 3), 150.0);
        // #2: balancedBowl off-resonance — Lean: 5.
        assert_eq!(balanced.q_filter(10.0, 7), 5.0);
        // #3: highDampingBowl off-resonance — Lean Nat: 0, Rust f32: 0.1
        // (documented arithmetic gap; the qualitative claim agrees).
        let high_damp = BowlMeshHead::new(5, 5, 3, 99, 3, 8);
        let mask_out = high_damp.q_filter(10.0, 7);
        assert!((mask_out - 0.1).abs() < 1e-6);
        // #4: pejorativeBowl Q — Lean: 1000.
        let pejorative = BowlMeshHead::new(10, 2, 100, 1, 0, 8);
        assert_eq!(pejorative.q_factor(), 1000);
        assert!(pejorative.is_pejorative_echo());
        // #5: filledBowl fundamental — Lean: 0.
        let filled = BowlMeshHead::new(5, 0, 3, 1, 0, 8);
        assert_eq!(filled.fundamental_mode(), 0);
        assert!(filled.is_filled_bowl());
    }

    /// `for_sweep` parity: fills the bowl with `balancedBowl` defaults
    /// (5, 5, 3) and matches the documentary `fundamental_dim` to the
    /// intrinsic `fundamental_mode()` (= 3). The returned head must
    /// have `q_factor = 15` (same as `balancedBowl`) at `damping = 1`,
    /// and `apply` must round-trip through `route_residual`
    /// non-destructively for non-zero input.
    #[test]
    fn for_sweep_constructor_matches_balanced_bowl() {
        let head = BowlMeshHead::for_sweep(3584, 1);
        assert_eq!(head.rim, 5);
        assert_eq!(head.void, 5);
        assert_eq!(head.rigidity, 3);
        assert_eq!(head.damping, 1);
        assert_eq!(head.fundamental_dim, 3);
        assert_eq!(head.fundamental_mode(), 3);
        assert_eq!(head.hidden_dim, 3584);
        assert_eq!(head.q_factor(), 15);

        let input = vec![1.0_f32; 3584];
        let out = head.apply(&input);
        assert_eq!(out.len(), 3584);
        // On-resonance dim (= fundamental_mode = 3) is amplified by
        // q_factor = 15.
        assert!((out[3] - 15.0).abs() < 1e-6);
        // Off-resonance dims (everything but index 3) are halved
        // (damping + 1 = 2).
        assert!((out[0] - 0.5).abs() < 1e-6);
        assert!((out[1792] - 0.5).abs() < 1e-6);
        // Apply is non-mutating on the input slice.
        assert_eq!(input[0], 1.0);
    }
}
